#include <bits/stdc++.h>
using namespace std;
const int N=500005;
int n,d,k,dp[N],mx;
struct node
{
	int x,num;
} a[N];
deque<int> dq;
void add(int x)
{
	while(!dq.empty()&&dp[dq.back()]<=dp[x])
	{
//		cout<<dq.back()<<" ";
		dq.pop_back();
	}
	dq.push_back(x);
}
bool check(int mid)
{
//	cout<<mid<<" :\n";
	memset(dp,128,sizeof(dp));
	int l=max(1,d-mid),r=d+mid;
	dp[1]=0;
	for(int i=1;i<=n;i++)
	{
		dp[i]+=a[i].num;
//		cout<<"		"<<dp[i]<<" :\n 	";
		if(dp[i]>=k) return 1;
		int ll=a[i].x+l,rr=a[i].x+r;
		for(int j=i+1;j<=n;j++)
		{
			if(a[j].x>rr) break;
			if(a[j].x<ll) continue;
//			cout<<j<<" ";
			dp[j]=max(dp[j],dp[i]);
		}
//		cout<<"\n";
	}

	return 0;
}
void clear()
{
	while(!dq.empty()) dq.pop_front();
}
bool check2(int mid) //正解 
{
//	cout<<mid<<" :\n";
	clear();
	if(a[1].num>=k) return 1;
	queue<int> q;
	q.push(1);
	dp[1]=a[1].num;
	int l=max(1,d-mid),r=d+mid;
//	cout<<"  l : "<<l<<"  r : "<<r<<"\n";
//	cout<<" dp 1 :"<<dp[1]<<"\n";
	for(int i=2;i<=n;i++)
	{
//		cout<<i<<" : ";
//		cout<<i<<"  del : ";
		int tim=a[i].x;
		while(!q.empty()&&tim>=a[q.front()].x+l)
		{
			add(q.front());
			q.pop();
		}
		while(!dq.empty()&&tim>a[dq.front()].x+r)
		{
//			cout<<dq.front()<<" ";
			dq.pop_front();
		}
//		cout<<"\n";
//		cout<<dq.front()<<"  <- front\n";
		if(dq.empty())
		{
//			cout<<"-\n";
			continue;
		}
		q.push(i);
		dp[i]=dp[dq.front()]+a[i].num;
//		cout<<dp[i]<<"\n";
		if(dp[i]>=k)
		{
//			cout<<"    YES" ;
			return 1;
		}
	}
	return 0;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>d>>k;
	n++;
	a[1].num=0,a[1].x=0;
	for(int i=2;i<=n;i++)
	{
		cin>>a[i].x>>a[i].num;
		mx=max(mx,a[i].x);
	}
	long long l=0,r=mx,mid;
	while(l<=r)
	{
//		if(check(mid)!=check2(mid))
//		{
//			cout<<"NO!!!";
//			return 0;
//		}
		mid=(l+r)/2;
		if(check2(mid)) r=mid-1;
		else l=mid+1;
//		cout<<"\n";
	}
	if(r==mx) cout<<-1;
	else cout<<r+1;
	return 0;
}
